module d_flip_flop(
    input wire clk,
    input wire reset,
    input wire enable,
    input wire d,
    output reg q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset)
        q <= 1'b0;
    else if (enable)
        q <= d;
end

endmodule
